import React from 'react';
import SignInPage from './js/components/SignInPage/SignInPage';
import RegisterPage from './js/components/RegisterPage/RegisterPage.js';

import { useState } from "react";

const App = () => {
  const page = window.location.hash.replace('#', '') || 'SignInPage';

  const showPage = (newPage: string) => {
    window.location.hash = newPage;
  };

  return(
    (<div>
      {page === 'SignInPage' && <SignInPage showPage={showPage} />}
    </div>)
  );
}

export default App;
